export type NotoSerifDisplayWeight =
  | "100"
  | "200"
  | "300"
  | "400"
  | "500"
  | "600"
  | "700"
  | "800"
  | "900";
export type NotoSerifDisplayStyle = "italic" | "normal";
export type NotoSerifDisplaySubset =
  | "cyrillic"
  | "cyrillic-ext"
  | "greek"
  | "greek-ext"
  | "latin"
  | "latin-ext"
  | "vietnamese";
export type NotoSerifDisplayOptions = GoogleFontOptions<
  NotoSerifDisplayWeight,
  NotoSerifDisplayStyle,
  NotoSerifDisplaySubset
>;

/**
 * Noto Serif Display — Google font. Pass `weights`/`styles` to register a subset of
 * faces (omit for all) and `subset` to choose the character set (default "latin").
 */
export default class NotoSerifDisplay extends GoogleFont<
  NotoSerifDisplayWeight,
  NotoSerifDisplayStyle,
  NotoSerifDisplaySubset
> {
  constructor(options?: NotoSerifDisplayOptions) {
    super(FAMILY, FACES, options);
  }
}
